use postgres::{Client, NoTls};

fn search_users_by_email(email: &str) -> Vec<User> {
    let mut client = Client::connect("host=localhost user=postgres password=password", NoTls).unwrap();
    let mut stmt = client.prepare("SELECT * FROM users WHERE email = $1").await.unwrap();
    let rows = stmt.query(&[&email]).await.unwrap();

    let mut results: Vec<User> = vec![];
    for row in rows {
        let user = User {
            id: row.get(0),
            email: row.get(1),
            name: row.get(2),
        };
        results.push(user);
    }

    return results;
}